(window.webpackJsonp=window.webpackJsonp||[]).push([[6],{225:function(a,v,t){"use strict";t.r(v);var n=t(15),r=t(0);function e(a){return(e="function"==typeof Symbol&&"symbol"==typeof Symbol.iterator?function(a){return typeof a}:function(a){return a&&"function"==typeof Symbol&&a.constructor===Symbol&&a!==Symbol.prototype?"symbol":typeof a})(a)}r.a.config.optionMergeStrategies;var i={VueRemarkRoot:{name:"VueRemarkRoot",render:function(a){return a("div",null,this.$slots.default)}}},o=function(a){var v=a.options.components=a.options.components||{},t=a.options.computed=a.options.computed||{};Object.keys(i).forEach((function(a){"object"===e(i[a])&&"function"==typeof i[a].render?v[a]=i[a]:t[a]=function(){return i[a]}}))},J=r.a.config.optionMergeStrategies,D="__vueRemarkFrontMatter",_={excerpt:null,title:"История развития JAVA",category:"ui",description:"Чтобы писать автотесты на языке Java потребуется установить пакет Oracle JDK или Open JDK. В этой статье мы расскажем в чем между ними различия, что лучше устанавливать, а также пройдемся по шагам для установки и настройке рабочей среды.",tags:["java","ui"],icon:"fab fa-java",image:"",date:"2019-11-04T00:00:00.000Z",keywords:"история развития java, java"};var p=function(a){a.options[D]&&(a.options[D]=_),r.a.util.defineReactive(a.options,D,_),a.options.computed=J.computed({$frontmatter:function(){return a.options[D]}},a.options.computed)},s=Object(n.a)({},(function(){var a=this,v=a.$createElement,t=a._self._c||v;return t("VueRemarkRoot",[t("h2",{attrs:{id:"предпосылки-создания-языка"}},[t("a",{attrs:{href:"#%D0%BF%D1%80%D0%B5%D0%B4%D0%BF%D0%BE%D1%81%D1%8B%D0%BB%D0%BA%D0%B8-%D1%81%D0%BE%D0%B7%D0%B4%D0%B0%D0%BD%D0%B8%D1%8F-%D1%8F%D0%B7%D1%8B%D0%BA%D0%B0","aria-hidden":"true"}},[a._v("#")]),a._v("Предпосылки создания языка")]),t("p",[a._v("1990 год - время когда шел расцвет персональных компьютеров. На тот момент компания Sun испытывала трудности посколько концентрировалась главным образом на производстве серверов и высокопроизводительных станций. Машины Sun были слишком сложными для массового пользователя. \nВ это время, Патрик Нотон - уважаемый 25-летний программист Sun заявил о своем решении уйти в компанию NeXT Computer Inc. На что, президент и CEO корпорации Sun, Скотт МакНили попросил Нотона написать всё что по его мнению в Sun делается неправильно и предложить своё решение, так как если бы тот был Богом.")]),t("p",[a._v("Нотон выполнил просьбу и сформировал список недостатков Sun, а также выразил предложения по необходимым изменениям. После получения, МакНили переслал его отчет всей цепочке управления.\nОказалось что Нотон описал всё то, о чем все думали но боялись признаться. Также его поддержал Билл Джой (Bill Joy) - один из основателей и вице-президент Sun и Джеймс Гослинг(James Gosling), замечательный программист, чье мнение имело значение.\nКак итог, группа технических специалистов, объединившись, сформировала основные концепции нового проекта, а Джон Гейдж (John Gage), руководитель научных исследований Sun, представил проект высшему руководству компании.")]),t("h3",{attrs:{id:"проект-green"}},[t("a",{attrs:{href:"#%D0%BF%D1%80%D0%BE%D0%B5%D0%BA%D1%82-green","aria-hidden":"true"}},[a._v("#")]),a._v("Проект Green")]),t("p",[a._v("Таким образом, 1 февраля 1991 года Патрик Нотон, Джеймс Гослинг и Майк Шеридан (Mike Sheridan) вплотную приступили к реализации проекта, который получил название Green.")]),t("p",[a._v("На ежегодном собрании Гослинг сделал следущие замечания:")]),t("ol",[t("li",[a._v("компьютерные чипы имеют большое распространение в разнообразной технике")]),t("li",[a._v("у людей накапливается большое количество пультов управления")])]),t("p",[a._v("Как следствие этих замечаний родилась идея сделать устройство с ЖК дисплеем через которое с помощью интуитивно понятного интерфейса можно управлять всеми устройствами сразу.")]),t("p",[a._v("Сказано - сделано: Нотон начал работать над специализированной графической системой, Гослинг взялся за программное обеспечение, а Шеридан занялся бизнес-вопросами.")]),t("p",[a._v("В процессе работы выяснилось, что устройства с которыми предстоит иметь дело, построены на разнообразных процессорах, поэтому разработка функциональности потребует учитывать всевозможные ограничения используемых чипов. Решением могло стать объединение сетей, компьютеров и других устройств в единую инфраструктуру.\nСначала была предпринята попытка модифицировать язык C++, но выяснилось что хоть C++ славился своей скоростью, однако основной проблемой стала его ненадежность, что было очень критично для поставленных целей.")]),t("h2",{attrs:{id:"кто-и-для-чего-создал-язык-java"}},[t("a",{attrs:{href:"#%D0%BA%D1%82%D0%BE-%D0%B8-%D0%B4%D0%BB%D1%8F-%D1%87%D0%B5%D0%B3%D0%BE-%D1%81%D0%BE%D0%B7%D0%B4%D0%B0%D0%BB-%D1%8F%D0%B7%D1%8B%D0%BA-java","aria-hidden":"true"}},[a._v("#")]),a._v("Кто и для чего создал язык Java")]),t("p",[a._v("В июне 1991 года Гослинг начинает разработку нового языка программирования. Название этот язык получил в честь растущего за окном дерева - Oak(дуб). Новое устройство получило название *7 (Star 7). Также был разработан забавный персонаж Duke, который в последствии стал символом языка Java. Для разработки Star7 была открыта новая компания с названием First Person.")]),t("p",[a._v('4 сентября 1992года Star7 был завершен - это было небольшое устройство с 5" цветным сенсорным экраном без кнопок! Технологией заинтересовались крупные компании производители. Однако оказалось, что стоимость подобного устройства составляла не менее 50%, а производители бытовой техники не привыкли платить большие деньги за дополнительную функциональность, облегчающую использование их продуктов. Затем была пара не успешных попыток продвинуть Oak на рынок интерактивного телевидения, которые также не увенчались успехом.')]),t("p",[a._v("В апреле 1993года выходит первая версия графического браузера обозревателя Mosaic 1.0 для WWW. Его особенностью было то что он основывался на новом языке гипертекстовой разметки. Этот формат поддерживал текст, изображения и самое главное ссылки. Все это было бесплатно и количество документов в сети росло экспоненциально. Поэтому FirstPerson  разрабатывает новый план, который был промежуточным шагом от интерактивного телевидения к возможностям Internet. Но этот план не устроил руководство Sun (он не вполне соответствовал главному ожиданию - новая разработка должна была привести к увеличению спроса на продукты Sun). ")]),t("p",[a._v('В этот момент создатели FirstPerson, наконец, обратили внимание на Internet, они поняли, что функциональность тех сетевых приложений, для которых создавался OaK, очень близка к WWW. Этот факт плюс возможность бесплатного распространения убедили руководство Sun, что Internet поможет воскресить платформу OaK. Начинается новый проект с названием LiveOak. Гослинг пересматривает программный код платформы, а Нотон берется за написание "убойного" приложения,которое сразу бы продемонстрировало всю мощь OaK для Internet.')]),t("p",[a._v("Особенности языка Oak отвечали предъявляемым требованиям Internet-программирования:")]),t("ul",[t("li",[a._v("безопасность")]),t("li",[a._v("объем")]),t("li",[a._v("сложность")])]),t("p",[a._v("Для демонстрации приложений написанных на языке Oak требовался браузер, который был написан Нотоном и получил название WebRunner. Небольшие программы, написанные на OaK для распространения через Internet, назвали апплетами ( applets ).\nВо время демонстрации на конференции посвященной разработке  Internet приложений все были поражены интерактивным возможностям языка Оба аплета показанные на этой конференции входят в состав Java Development Kit любой версии.")]),t("p",[a._v("В начале 1995 года, когда стало ясно, что официальное объявление уже не за горами, за дело взялись маркетологи. В результате их исследований OaK был переименован в Java"),t("footnote",{attrs:{num:"1",message:"Также рассматривались - Neon, Lyric, Pepper или Silk"}}),a._v(', а WebRunner стал называться HotJava. Легенда гласит, что Java - это сорт кофе (такой кофе действительно есть), который очень любили программисты. Видимо, похожим образом родилось и название HotJava ("горячая Java "). Тема кофе навсегда останется в названиях и логотипах ( технология создания компонентов названа Java Beans - зерна кофе, специальный формат для архивирования файлов с Java -программами JAR - банка с кофе и т.д.), а сам язык критики стали называть "для кофеварок".')],1),t("h2",{attrs:{id:"применение-во-время-развития-интернета"}},[t("a",{attrs:{href:"#%D0%BF%D1%80%D0%B8%D0%BC%D0%B5%D0%BD%D0%B5%D0%BD%D0%B8%D0%B5-%D0%B2%D0%BE-%D0%B2%D1%80%D0%B5%D0%BC%D1%8F-%D1%80%D0%B0%D0%B7%D0%B2%D0%B8%D1%82%D0%B8%D1%8F-%D0%B8%D0%BD%D1%82%D0%B5%D1%80%D0%BD%D0%B5%D1%82%D0%B0","aria-hidden":"true"}},[a._v("#")]),a._v("Применение во время развития интернета")]),t("p",[a._v("Несмотря на то что изначально спецификации, реализацию платформы и HotJava планировалось свободно распространять через интернет, на конец 1994 за пределы Sun ушло лишь несколько копий. Поэтому вскоре выходит первый пресс релиз о том, что скоро выйдут первые версии OaK и WebRunner после чего интерес к продукту начал расти лавинообразно.\nДля предоставлении информации о Java создается веб сайт существующий и по сей день java.sun.com. Официальное представление Java состоялось на конференции SunWorld. Здесь же после того как были представлены технологии Java и HotJava было объявлено, что новая версия самого популярного на тот момент браузера Netscape Navigator будет поддерживать Java, что означало, что Java становиться частью WWW как HTML.")]),t("p",[a._v("С этих пор основная линия развиития начинает быть связана с браузерами. Этому способствовали следущие факторы:")]),t("ul",[t("li",[a._v("Тк под разными платформами работали разные браузеры, было сложно поддерживать единообразие страниц на разных клиентах. Java успешно решала эту проблему. ")]),t("li",[a._v("С её помощью страницу можно было наполинть не только текстом но и динамиескими элементами, а также создать сложный пользовательский интерфейс()")]),t("li",[a._v("В отличие от обычных программ аплеты получили важное овйство HTML страниц прочитав содержимой такой страницы не сохраняя ее на свой компьютер клиент на следущий день может прочитать уже обновленное содержание.")]),t("li",[a._v("Пользователь непривязан к своему рабочему месту и может открыть нужную страницу с любого компьютера, в том числе в любом internet кафе без страха подцепить вирус.")]),t("li",[a._v("Java поддерживался в самом популярном браузере Netscape и также предлагала HotJava,  доступный на любой платформе.")])]),t("p",[a._v("Однако впоследствии, как известно, самый распространенным браузером стал Microsoft Internet Explorer. Этому способствовало следущее:")]),t("ul",[t("li",[a._v("7 декабря 1995 года Microsoft объявляет о своем намерении лицензировать Java, а в марте 1996 года соглашение о лицензировании было подписано.")]),t("li",[a._v("поддержка независимой организации W3C, которая руководила разработкой нового стандарта HTML 3. Microsoft смогла утвердить стандарты, которые отличались от уже реализованных в Netscape Navigator, причем отличия порой были чисто формальными. В результате оказалось, что страницы,созданные в соответствии с W3C-спецификациями, отображались в Navigator искаженно. ")]),t("li",[a._v("NN необходимо было скачивать (пусть и бесплатно) и устанавливать вручную, а IE быстро стал встроенным компонентом Windows, готовым к использованию (и от которого, кстати, избавиться нельзя было принципиально).\nПро HotJava, к сожалению, сказать особенно нечего. Некоторое время Sun поддерживала этот продукт и добавила возможность визуально генерировать web-страницы без знания HTML. Однако создать конкурентоспособный браузер не удалось и вскоре развитие HotJava было остановлено. Сейчас еще можно скачать и посмотреть последнюю версию 3.0.")])]),t("h2",{attrs:{id:"сравнение-с-языками-c-c-c-javascript-groovy-kotlin"}},[t("a",{attrs:{href:"#%D1%81%D1%80%D0%B0%D0%B2%D0%BD%D0%B5%D0%BD%D0%B8%D0%B5-%D1%81-%D1%8F%D0%B7%D1%8B%D0%BA%D0%B0%D0%BC%D0%B8-c-c-c-javascript-groovy-kotlin","aria-hidden":"true"}},[a._v("#")]),a._v("Сравнение с языками C, C++, C#, JavaScript, Groovy, Kotlin")]),t("p",[t("strong",[a._v("JavaScript")])]),t("p",[a._v("JavaScript, до сих пор многие связывают с Java, видимо, по причине схожести имен.")]),t("p",[a._v("Сходства:")]),t("ol",[t("li",[a._v("Оба языка были объявлены компаниями Sun и Netscape с интервалом в несколько месяцев.")]),t("li",[a._v("Вышедший вскоре после этого Netscape Navigator 2.0 поддерживал обе новые технологии. ")]),t("li",[a._v("JavaScript, как и Java - открытый кроссплатформенный объектный язык сценариев для корпоративных сетей и Internet.")]),t("li",[a._v('Возможно, само название Java Script было дано для того, чтобы воспользоваться популярностью Java, либо для того, чтобы еще больше расширить понятие "платформа Java ". Java Script, с одной стороны, расширяет и дополняет HTML, а с другой стороны - дополняет Java. С помощью Java пишутся объекты- апплеты, которыми можно управлять через язык сценариев.')])]),t("p",[a._v("Различия:")]),t("ol",[t("li",[a._v("Java и Java Script - совершенно различные языки, и в первую очередь - по назначению. Если изначально Java позиционировался как язык для создания Internet-приложений ( апплетов ), то сейчас уже очевидно, что Java - это полноценный язык программирования. Что касается Java Script, то он полностью оправдывает свое название языка сценариев, оставаясь расширением HTML. ")])]),t("p",[t("strong",[a._v("С/C++")])]),t("p",[a._v("Сходства:")]),t("ol",[t("li",[a._v("Синтаксис Java действительно создан на основе синтаксиса языков C/C++, так что если посмотреть на исходный код программ, написанных на этих языках и на Java, то не сразу удается понять, какая из них на каком языке написана. \nЭто почему-то дало многим повод думать, что Java - это упрощенный C++ с дополнительными возможностями, такими как garbage collector. Автоматический сборщик мусора ( garbage collector ) мы рассмотрим чуть ниже, но считать, что Java такой же язык, как и C++,- большое заблуждение.")])]),t("p",[a._v("Различия:")]),t("ol",[t("li",[a._v("С++ принципиально не годился для новых задач, которые поставили себе разработчики из компании Sun, поэтому модель Java была построена заново, причем в соответствии с совсем другими целями. Дальнейшие лекции будут постепенно раскрывать конкретные различия.")]),t("li",[a._v("Что же касается объектной модели, то она скорее была построена по образцу таких языков, как Smalltalk от IBM, или разработанный еще в 60-е годы в Норвежском Вычислительном Центре язык Simula, на который ссылается сам создатель Java Джеймс Гослинг.")]),t("li",[a._v("Авторы Java потрудились избавить программистов от наиболее распространенных ошибок, которые порой допускают даже опытные разработчики на C/C++. И первое место здесь занимает работа с памятью.")])]),t("p",[t("strong",[a._v("C#")])]),t("p",[a._v("Сходства:")]),t("ol",[t("li",[a._v("Используется один и тот же общий синтаксис")]),t("li",[a._v("Поддерживается распределенное программирова­ние")]),t("li",[a._v("Применяется одна и та же объектная модель")])]),t("p",[a._v("Различия:")]),t("ol",[t("li",[a._v("C# создан в корпорации Microsoft и в отличие от Java используется преимущественно для поддержки платформы .NET Framework ")])]),t("h2",{attrs:{id:"основные-версии-и-их-особенности"}},[t("a",{attrs:{href:"#%D0%BE%D1%81%D0%BD%D0%BE%D0%B2%D0%BD%D1%8B%D0%B5-%D0%B2%D0%B5%D1%80%D1%81%D0%B8%D0%B8-%D0%B8-%D0%B8%D1%85-%D0%BE%D1%81%D0%BE%D0%B1%D0%B5%D0%BD%D0%BD%D0%BE%D1%81%D1%82%D0%B8","aria-hidden":"true"}},[a._v("#")]),a._v("Основные версии и их особенности")]),t("p",[a._v("Впервые Java была объявлена 23 мая 1995 года. \nОсновными продуктами, доступными на тот момент в виде бета-версий, были: ")]),t("ul",[t("li",[a._v("Java language specification, JLS, спецификация языка Java (описывающая лексику, типы данных, основные конструкции и т.д.);")]),t("li",[a._v("спецификация JVM; ")]),t("li",[a._v("Java Development Kit, JDK - средство разработчика, состоящее в основном из утилит, стандартных библиотек классов и демонстрационных примеров.")])]),t("p",[a._v("Спецификация JVM предназначена в первую очередь для создателей виртуальных машин, а потому практически не используется Java-программистами.")]),t("p",[a._v("JDK долгое время было базовым средством разработки приложений. Оно не содержит никаких текстовых редакторов, а оперирует только уже существующими Java-файлами. \nКомпилятор представлен утилитой javac ( java compiler). Виртуальная машина реализована программой java. \nДля тестовых запусков апплетов существует специальная утилита appletviewer. Наконец, для автоматической генерации документации на основе исходного кода прилагается средство javadoc.")]),t("p",[a._v("Первая версия содержала всего 8 стандартных библиотек:")]),t("p",[t("strong",[a._v("java.lang")]),a._v(" - базовые классы, необходимые для работы любого приложения (название - сокращение от language);"),t("br"),t("strong",[a._v("java.util")]),a._v(" - многие полезные вспомогательные классы;"),t("br"),t("strong",[a._v("java.applet")]),a._v(" - классы для создания апплетов ;"),t("br"),t("strong",[a._v("java.awt, java.awt.peer")]),a._v(" - библиотека для создания графического интерфейса пользователя ( GUI ), называется Abstract Window Toolkit, AWT;"),t("br"),t("strong",[a._v("java.awt.image")]),a._v(" - дополнительные классы для работы с изображениями;"),t("br"),t("strong",[a._v("java.io")]),a._v(" - работа с потоками данных (streams) и с файлами;"),t("br"),t("strong",[a._v("java.net")]),a._v(" - работа с сетью."),t("br")]),t("p",[a._v("Таким образом, все библиотеки начинаются с java, именно они являются стандартными. Все остальные (начинающиеся с com, org и др.) могут меняться в любой версии без поддержки совместимости.")]),t("p",[a._v("Финальная версия JDK 1.0 была выпущена в январе 1996 года.")]),t("p",[a._v("Когда стало понятно, что новая технология пользуется небывалым спросом, разработчикам захотелось укрепить и развить успех и распространенность Java. Компания Sun старалась наладить сотрудничество с независимыми фирмами для производства различных библиотек, средств разработчика, инструментов.")]),t("p",[a._v('9 января 1996 года было сформировано новое подразделение JavaSoft, которое и занялось разработкой новых Java-технологий и продвижением их на рынок. Главная цель - появление все большего количества самых разных приложений, написанных на этой платформе. Например, 1 июля 1997 года было объявлено, что ученые NASA (National Aeronautics and Space Administration, государственная организация США, занимающаяся исследованием космоса) с помощью Java - апплетов управляют роботом, изучающим поверхность Марса ("Java помогает делать историю!").')]),t("p",[a._v("Поясним систему именования версий. Обозначение версии состоит из трех цифр. Если у двух версий первая цифра одинаковая, то это означает, что программа, написанная на более старом JDK, всегда успешно выполнится на более новом. По возможности соблюдается и обратная совместимость - если программа откомпилирована более новым JDK, а никакие новые библиотеки не использовались, то в большинстве случаев старые виртуальные машины смогут выполнить такой код.")]),t("p",[a._v("Вторая цифра отображает существенное изменение(расширение) стандартных библиотек, а также добавление некоторых новых возможностей в сам язык, изменение утилит, входящие в JDK.")]),t("p",[a._v("Наконец, третья цифра означает развитие одной версии. В языке или библиотеках ничего не меняется, лишь устраняются ошибки, производится оптимизация, могут меняться (добавляться) аргументы утилит.")]),t("p",[a._v("С развитием версии какие-то функции или классы устаревают. Они объявляются deprecated, и хотя они будут поддерживаться до объявления новой версии, пользоваться ими не рекомендуется.")]),t("p",[t("strong",[a._v("JDK 1.0")])]),t("p",[a._v("минусы:")]),t("ul",[t("li",[a._v("производительность. Первая виртуальная машина работала очень медленно. Это связано с тем, что JVM, по сути, представляет собой интерпретатор, который работает всегда медленнее, чем исполняется откомпилированный код")]),t("li",[a._v("отмечались довольно бедные возможности AWT, отсутствие работы с базами данных и другие.")])]),t("p",[t("strong",[a._v("JDK 1.1")])]),t("p",[a._v("В декабре 1996 года объявляется новая версия JDK 1.1, сразу выкладывается для свободного доступа бета-версия. В феврале 1997 года выходит финальная версия. Что было добавлено в новом выпуске Java?")]),t("p",[a._v('Конечно, особое внимание было уделено производительности. Многие части виртуальной машины были оптимизированы и переписаны с использованием Assembler, а не C, как до этого. Кроме того, с октября 1996 года Sun развивает новый продукт - Just-In-Time компилятор, JIT. Его задача - транслировать Java байт-код программы в "родной" код операционной системы. Таким образом, время запуска программы увеличивается, но зато выполнение может ускоряться в некоторых случаях до 50 раз! С июля 1997 года появляется реализация под Windows и JIT стандартно входит в JDK с возможностью отключения.')]),t("p",[a._v("Были добавлены многие новые важные возможности:"),t("br"),a._v("\n1) JavaBeans - технология, объявленная еще в 1996 году, позволяет создавать визуальные компоненты, которые легко интегрируются в визуальные средства разработки."),t("br"),a._v("\n2) JDBC ( Java DataBase Connectivity) обеспечивает доступ к базам данных."),t("br"),a._v("\n3) RMI (Remote Method Invocation) позволяет легко создавать распределенные приложения."),t("br"),a._v("\n4) Были усовершенствованы поддержка национальных языков и система безопасности."),t("br"),a._v("\n5) С 11 марта 1997 года компания Sun начала предлагать Java Runtime Environment, JRE (среду выполнения Java ). По сути дела, это минимальная реализация виртуальной машины, необходимая для исполнения Java-приложений, \nбез компилятора и других средств разработки. Если пользователь хочет только запускать программы, это именно то, что ему нужно."),t("br"),a._v("\n6) В декабре 1996 года компании Sun и Netscape объявляют новую библиотеку IFC (Internet Foundation Classes), разработанную Netscape полностью на Java и предназначенную для создания сложного оконного интерфейса. "),t("br"),a._v("\nВ апреле 1997 года объявляется, что компании планируют объединить технологии AWT от Sun и IFC от Netscape для создания нового продукта Java Foundation Classes, JFC, в который должны войти:")]),t("ul",[t("li",[a._v("усовершенствованный оконный интерфейс, который получил особое название - Swing ;")]),t("li",[a._v("реализация Drag-and-Drop;")]),t("li",[a._v("поддержка 2D-графики, более удобная работа с изображениями;")]),t("li",[a._v("Accessibility API для пользователей с ограниченными возможностями")]),t("li",[a._v("и другие функции. ")])]),t("p",[a._v("Компания IBM также поддержала разработку новой технологии. В июле 1997 года стала доступна первая версия JFC. Первоначально библиотеки назывались, например, com.sun.java.swing для компонентов Swing.\nВ марте 1998 года вышла финальная версия этой технологии. За полгода продукт был скачан более 500.000 раз.")]),t("p",[a._v("На данный момент версия 1.1 считается полностью устаревшей и ее развитие остановилось на 1.1.8. Однако из-за того, что самый распространенный браузер MS IE до сих пор поддерживает только эту версию, она продолжает использоваться для написания небольших апплетов.")]),t("p",[t("strong",[a._v("Java 1.2")])]),t("p",[a._v("Выход следующей версии Java 1.2 много раз откладывался, но в итоге она настолько превзошла предыдущую 1.1, что ее и все последующие версии начали называть платформой Java 2 (хотя номера, конечно, по-прежнему отсчитывались как 1.х.х).")]),t("p",[a._v("Список появившихся возможностей очень широк, поэтому перечислим наиболее значимые из них:")]),t("p",[a._v("1) существенно переработанная модель безопасности, введены понятия политики (policy) и разрешения (permission);"),t("br"),a._v("\n2) JFC стал стандартной частью JDK, причем библиотеки стали называться, например, javax.swing для Swing (название javax указывает, что до этого библиотека считалась расширением Java );"),t("br"),a._v("\n3) полностью переработанная библиотека коллекций (collection framework) - классов для хранения набора объектов;"),t("br"),a._v("\n4) Java Plug-in был включен в JDK;"),t("br"),a._v('\n5) улучшения в производительности, глобализации (независимости от особенностей разных платформ и стран), защита от "проблемы-2000".'),t("br")]),t("p",[a._v("С февраля 1999 года исходный код самой JVM был открыт для бесплатного доступа всем желающим.")]),t("p",[a._v("Самое же существенное изменение произошло 15 июня 1999 года, спустя полгода после выхода JDK 1.2. На конференции разработчиков JavaOne компания Sun объявила о разделении развития платформы Java 2 на три направления:")]),t("ul",[t("li",[a._v("Java 2 Platform, Standard Edition ( J2SE ) - для использования на рабочих станциях и персональных компьютерах. Standard Edition - основа технологии Java и прямое развитие JDK (средство разработчика было переименовано в j2sdk).;")]),t("li",[a._v("Java 2 Platform, Enterprise Edition ( J2EE ) - для создания сложных, высоконадежных, распределенных серверных приложений. Условно можно сказать, что Enterprise Edition - это набор мощных библиотек (например, Enterprise Java Beans, EJB) и пример реализации платформы (сервера приложений, Application Server), которая их поддерживает. Работа такой платформы всегда опирается на j2sdk.;")]),t("li",[a._v("Java 2 Platform, Micro Edition ( J2ME ) - является усечением Standard Edition, чтобы удовлетворять жестким аппаратным требованиям небольших устройств, таких как карманные компьютеры и сотовые телефоны..")])]),t("p",[a._v("На самом деле, подобная классификация уже давно назрела, в частности, различных спецификаций и библиотек насчитывалось несколько десятков, а потому они нуждались в четкой структуризации. Кроме того, такое разделение облегчало развитие и продвижение на рынок технологии Java.")]),t("p",[a._v("Тем временем борьба за производительность продолжалась, и Sun пытался еще больше оптимизировать виртуальную машину. В марте 1999 года объявляется новый продукт - высокоскоростная платформа (engine) Java HotSpot. Была оптимизирована работа с потоками исполнения, существенно переработаны алгоритмы автоматического сборщика мусора ( garbage collector ) и многое другое. Ускорение действительно было очень существенным, всегда заметное невооруженным взглядом за несколько минут работы с Java-приложением.")]),t("p",[a._v("Новая платформа может работать в двух режимах - клиентском и серверном. Режимы различались настройками и другими оптимизирующими алгоритмами. По умолчанию работа идет в клиентском режиме.")]),t("p",[t("strong",[a._v("Java 1.3")])]),t("p",[a._v("Развитие HotSpot продолжалось более года, пока в начале мая 2000 года высокопроизводительная JVM не вошла в состав новой версии J2SE. \nВ эту версию было внесено еще множество улучшений и исправлений, но именно прогресс в скорости работы стал ключевым изменением нового j2sdk 1.3 (последняя подверсия 1.3.1).")]),t("p",[t("strong",[a._v("Java1.4")])]),t("p",[a._v("Версия J2SE 1.4 вышла в феврале 2002 года. Она была разработана для более полной поддержки web-сервисов (web services). Поэтому основные изменения коснулись работы с XML (Extensible Markup Language). Другое революционное добавление - выражение assert, позволяющее в отладочном режиме проверять верность условий, что должно серьезно упростить разработку сложных приложений. Наконец, были добавлены классы для работы с регулярными выражениями.")]),t("p",[a._v("В заключение для демонстрации уровня развития Standard Edition приведем стандартные диаграммы, описывающие все составляющие технологии, из документации к версиям 1.3 и 1.4.")]),t("p",[t("img",{attrs:{src:"https://www.intuit.ru/EDI/21_02_19_1/1550701182-19230/tutorial/57/objects/1/files/1-1.gif",alt:"1.3"}})]),t("p",[t("img",{attrs:{src:"https://www.intuit.ru/EDI/21_02_19_1/1550701182-19230/tutorial/57/objects/1/files/1-2.gif",alt:"1.4"}})]),t("p",[t("strong",[a._v("Java 1.5")])]),t("p",[a._v("В следующую версию Java, названную J2SE 5, был внесен ряд революционных изменений. В отличие от большинства предшествующих обновлений Java, которые предоставляли важные, но постепенные усовершенствования, в версии J2SE 5 была коренным образом расширена область, возможности и пределы применения язы­ка.\nОсновные из новых функ­циональных возможностей Java в данной версии:")]),t("ul",[t("li",[a._v("Обобщения.")]),t("li",[a._v("Аннотации.")]),t("li",[a._v("Автоупаковка и автораспаковка.")]),t("li",[a._v("Перечисления.")]),t("li",[a._v("Усовершенствованный цикл for в стиле for each. ")]),t("li",[a._v("Аргументы переменной длины (varargs). ")]),t("li",[a._v("Статический импорт.")]),t("li",[a._v("Форматированный ввод-вывод.")]),t("li",[a._v("Утилиты параллельной обработки.")])]),t("p",[a._v("Значение новых функциональных возможностей нашло отражение в присвоен­\nном данной версии номере - \"5': Если следовать привычной логике, то следующим номером версии Java должен был быть 1.5. Однако новые средства оказались столь значительными, что переход от версии 1.4 к версии 1.5 не отражал бы масштабы внесенных изменений. Поэтому в компании Sun Micгosystems решили присвоить новой версии номер 5, чтобы тем самым подчеркнуть значимость этого события. Поэтому версия данного программного продукта была названа J2SE 5, а комплект разработчика - JDK 5. Тем не менее для сохранения единообразия в компании Sun Microsystems решили использовать номер 1.5 в качестве внутреннего номера версии, называемого также номером версии разработки. Цифра 5 в обозначении версии называется номером версии продукта.")]),t("p",[t("strong",[a._v("Java 1.6")])]),t("p",[a._v("Версия Java SE 6 была построена на основе версии J2SE 5 с рядом дальнейших усовершенствований. Она не содержала дополнений к числу основных языковых средств Java, но расширяла библиотеки API, добавляя несколько новых пакетов и предоставляя ряд усовершенствований в исполняющей системе. ")]),t("p",[t("strong",[a._v("Java 1.7")])]),t("p",[a._v('Это был первый главный выпуск Java с тех пор, как компания Sun Microsystems была приобретена компанией Oracle.Новые языковые средства были разработаны в рамках проекта Project Coin. Этот проект должен был обозначать многие так называемые "мелкие" изменения в Java, которые предполагалось включить в JDK 7.\nНовые языковые средства, внедренные в JDK 7:')]),t("ul",[t("li",[a._v("Расширение типа String возможностями управлять ветвлением в операторе switch.")]),t("li",[a._v("Двоичные целочисленные литералы.")]),t("li",[a._v("Символы подчеркивания в числовых литералах.")]),t("li",[a._v("Расширение оператора try, называемое оператором try сресурсами, обе­ спечивающее автоматическое управление ресурсами. (Например, потоки ввода-вывода могут теперь быть закрыты автоматически, когда они больше не нужны.)")]),t("li",[a._v("Выводимость типов (с помощью ромбовидного оператора <>) при создании обобщенного экземпляра.")]),t("li",[a._v("Улучшенная обработка исключений, благодаря которой два исключения или\nбольше могут быть обработаны в одном блоке оператора catch (многократ­ный перехват), а также улучшенный контроль соответствия типов повторно генерируемых исключений.")]),t("li",[a._v("Улучшение предупреждений компилятора, связанных с некоторыми типами ме­тодов с переменным количеством аргументов. И хотя это нельзя считать изме­нением в синтаксисе, оно дает больший контроль над предупреждениями.")])]),t("p",[a._v("В версии Java SE 7 внесено несколько дополнений в библиотеку Java API. Важнейшими из них являются усовершенствования каркаса NIO Framework и до­ полнения каркаса Fork/Join Framework.Каркас Fork/Join Framework обеспечивает важную поддержку параллельного программирования. Термином параллельное программирование обычно обозна­ чаются технологии, повышающие эффективность применения компьютеров с не­ сколькими процессорами, включая многоядерные системы.  Новая система ввода-вывода NIO (перво­ начально называвшаяся New 110) была внедрена в версии Java 1.4. Но изменения, внесенные в версии Java SE 7, значительно расширили возможности этой системы, причем настолько, что она зачастую обозначается как NI0.2.")]),t("p",[t("strong",[a._v("Java 1.8")])]),t("p",[a._v("Значительные усовершенствования в ней про­ изошли благодаря внедрению лямбда-выражений - нового языкового средства с далеко идущими последствиями.  Лямбда-выражения вносят в Java возможности функционального программирования. В процессе программирования лямбда-выражения способны упростить и сократить объем исходного кода, требующегося для создания опреде­ ленных конструкций, в том числе некоторых типов анонимных классов. Кроме того, лямбда-выражения вводят в язык новую операцию ( - >) и элемент синтаксиса.\nВнедрение лямбда-выражений оказало обширное влияние и на библиотеки Java, которые были дополнены новыми средствами:\n1. новый прикладной программный интерфейс API потоков ввода-вывода, входящий в па­кет java.util.stream. В этом прикладном интерфейсе API, оптимизированном\nс учетом лямбда-выражений, поддерживаются конвейерные операции с данными.\n2. Пакет java.util.function, в котором оперделен целый ряд функциональных интерфейсов, обеспечивающих поддержку лямбда-выражений.\n3. появилась возможность определять реализацию по умолчанию метода, объявленного в интерфейсе. Если конкретная реализация такого метода отсутствует, то используется его реализация по умолчанию в интерфейсе. ")]),t("p",[a._v("К числу других средств, появившихся в JDK 8, относятся новый прикладной программный интерфейс API для обработки даты и времени, типовые аннотации и возможность использовать параллельную обработку при сортировке массива. Кроме того, в состав JDK 8 включена поддерж­ ка JavaFX 8 - последней версии нового каркаса приложений Java с графическим пользовательским интерфейсом (ГПИ). Предполагается, что каркас JavaFX ста­ нет неотъемлемой частью практически всех приложений Java и в конечном итоге заменит Swing для разработки большинства проектов на основе ГПИ.")]),t("p",[t("strong",[a._v("Java 1.9")])]),t("p",[a._v("Главным нововведением в версии JDK 9 являются модули, позволяющие указы­ вать взаимосвязи и зависимости в прикладном коде, а также расширяющие воз­ можности управления доступом в Java. Вместе с модулями в языке Java появился новый синтаксический элемент и несколько ключевых слов. Кроме того, в состав JDK была включена утилита j link, позволяющая создавать на стадии выполне­ ния образ прикладного файла типа JMOD, содержащего только нужные модули. Модули также оказали заметное влияние на библиотеку Java API, поскольку, на­ чиная с версии JDK 9, библиотечные пакеты организованы в модули.")]),t("p",[a._v("Помимо модулей, в состав JDK 9 вошло многих других новых средств. Особый интерес представляет утилита JShell, поддерживающая экспериментирование\nс программами и изучение языка Java в интерактивном режиме. \nЕще одним интересным новшеством является поддержка закрытых интерфейсных методов. Их внедрение дополнительно расширило поддержку методов с реализацией по умолчанию, по­\nявившихся в версии JDK 8. В версии JDK 9 возможности утилиты javadoc были расширены средствами поиска, а также новым дескриптором @index для их под­ держки. Как и в предыдущих выпусках, в версии JDK 9 были продолжены усовер­ шенствования библиотек Java API.")]),t("p",[a._v("Версии JDK 9 присуща одна существенная осо­бенность - упразднение аплетов. Начиная с вверсии JDK 9, аплеты больше не реко­мендованы для применения в новых проектах, поскольку аплеты больше не поддерживаются в браузерах, а также по ряду других причин.В настоящее время для развертывания прикладных программ на Java в Интернете рекомендуется технология Java Web Staгt.")]),t("h2",{attrs:{id:"платформа-java"}},[t("a",{attrs:{href:"#%D0%BF%D0%BB%D0%B0%D1%82%D1%84%D0%BE%D1%80%D0%BC%D0%B0-java","aria-hidden":"true"}},[a._v("#")]),a._v("Платформа Java")]),t("p",[a._v('Как правило, платформой называют сочетание аппаратной архитектуры ("железо"), которая определяется типом используемого процессора (Intel x86, Sun SPARC, PowerPC и др.), с операционной системой (MS Windows, Sun Solaris, Linux, Mac OS и др.). При написании программ разработчик всегда пользуется средствами целевой платформы для доступа к сети, поддержки потоков исполнения, работы с графическим пользовательским интерфейсом ( GUI ) и другими возможностями. Конечно, различные платформы, в силу технических, исторических и других причин, поддерживают различные интерфейсы ( API, Application Programming Interface), а значит, и программа может исполняться только под той платформой, под которую она была написана.\nОднако часто заказчикам требуется одна и та же функциональность, а платформы они используют разные. Задача портирования приложений стоит перед разработчиками давно. \nА значит, и языки программирования должны быть изначально ориентированы на какую-то конкретную платформу. Синтаксис и основные концепции легко распространить на любую систему (хотя это и не всегда эффективно), но библиотеки, компилятор и, естественно, бинарный исполняемый код специфичны для каждой платформы. ')]),t("p",[a._v("Именно поэтому создатели Java задумали разработать не просто еще один язык программирования, а универсальную платформу для исполнения приложений, тем более что изначально OaK создавался для различных бытовых приборов, от которых ждать совместимости не приходится.")]),t("p",[a._v('Каким же образом можно "сгладить" различия и многообразие операционных систем? Способ не новый, но эффективный - с помощью виртуальной машины. Приложения на языке Java исполняются в специальной, универсальной среде, которая называется Java Virtual Machine. JVM - это программа, которая пишется специально для каждой реальной платформы, чтобы, с одной стороны, скрыть все ее особенности, а с другой - предоставить единую среду исполнения для Java-приложений. Фирма Sun и ее партнеры создали JVM практически для всех современных операционных систем. Когда речь идет о браузере с поддержкой Java, подразумевается, что в нем имеется встроенная виртуальная машина.')]),t("p",[a._v('Необходимо сказать, что разработчики Sun приложили усилия, чтобы сделать эту машину вполне реальной, а не только виртуальной. 29 мая 1996 года объявляется операционная система Java OS (финальная версия выпущена в марте следующего года). Согласно пресс-релизу, это была "возможно, самая небольшая и быстрая операционная система, поддерживающая Java ". Действительно, разработчики стремились к тому, чтобы обеспечить возможность исполнять Java-приложения на самом широком спектре устройств - сетевые компьютеры, карманные компьютеры (PDA), принтеры, игровые приставки, мобильные телефоны и т.д. Ожидалось, что Java OS будет реализована на всех аппаратных платформах. Это было необходимо для изначальной цели создателей Java - легкость добавления новой функциональности и совместимости в любые электрические приборы, которыми пользуется современный потребитель.')]),t("p",[a._v("Это был первый шаг, продвигающий платформу Java на один уровень вниз - на уровень операционных систем. Предполагалось сделать и следующий шаг - создать аппаратную архитектуру, центральный процессор, который бы напрямую выполнял инструкции Java безо всякой виртуальной машины. Устройство с такой реализацией стало бы полноценным Java-устройством.")]),t("p",[a._v("Кроме очевидных удобств, это начинание было с большим энтузиазмом поддержано индустрией и в силу того, что оно являлось сильнейшим оружием в борьбе с крупнейшим производителем программного обеспечения - Microsoft. ")]),t("p",[a._v('Вскоре разразился судебный скандал. 30 сентября 1997 года вышел новый IE 4.0, а уже 7 октября Sun объявила, что этот продукт не проходит тесты на соответствие со спецификацией виртуальной машины. 18 ноября Sun обращается в суд, чтобы запретить использование логотипа "Совместимый с Java " (" Java compatible") для MS IE 4.0. Оказалось, что разработчики Microsoft слегка "улучшили" язык Java, добавив несколько новых ключевых слов и библиотек. Не то что бы это были сверхмощные расширения, однако достаточно привлекательные для того, чтобы значительная часть разработчиков начала ее использовать. К счастью, в Sun быстро осознали всю степень опасности такого шага. Java могла потерять звание универсальной платформы, для которой верен знаменитый девиз "Write once, run everywhere" ("Написано однажды, работает везде"). В таком случае она утратила бы основу своего успеха, превратившись всего лишь в "еще один язык программирования".')]),t("p",[a._v("Компании Sun удалось отстоять свою технологию. 24 марта 1998 года суд согласился с требованиями компании (конечно, это было только предварительное решение, дело завершилось лишь 23 января 2001 года - Sun получил компенсацию в 20 миллионов долларов и добился выполнения лицензионного соглашения), а уже 12 мая Sun снова выступает с требованием: обязать Microsoft включить полноценную версию Java в Windows 98 и другие программные продукты. Эта тяжба продолжается до сих пор с переменным успехом сторон. ")]),t("p",[a._v("В результате Microsoft остановила свою поддержку Java на версии 1.1, которая на данный момент является устаревшей и не имеет многих полезных возможностей. Это, в свою очередь, практически остановило широкое распространение апплетов, кроме случаев либо совсем несложной функциональности (типа бегущей строки или диалога с несколькими полями ввода и кнопками), либо приложений для внутренних сетей корпораций. Для последнего случая Sun выпустил специальный продукт Java Plug-in, который встраивается в MS IE и NN, позволяя им исполнять апплеты на основе Java самых последних версий, причем полное соответствие спецификациям гарантируется (первоначально продукт назывался Java Activator и впервые был объявлен 10 декабря 1997 года)")]),t("p",[a._v("Что же касается сетевых компьютеров и Java OS, то, увы, они пока не нашли своих потребителей. Видимо, обычные персональные рабочие станции в совокупности с JVM требуют гораздо меньше технологических и маркетинговых усилий и при этом вполне успешно справляются с прикладными задачами. А Java, в свою очередь, стала позиционироваться для создания сложных серверных приложений.")]),t("h2",{attrs:{id:"основные-характеристики-и-принципы-языка"}},[t("a",{attrs:{href:"#%D0%BE%D1%81%D0%BD%D0%BE%D0%B2%D0%BD%D1%8B%D0%B5-%D1%85%D0%B0%D1%80%D0%B0%D0%BA%D1%82%D0%B5%D1%80%D0%B8%D1%81%D1%82%D0%B8%D0%BA%D0%B8-%D0%B8-%D0%BF%D1%80%D0%B8%D0%BD%D1%86%D0%B8%D0%BF%D1%8B-%D1%8F%D0%B7%D1%8B%D0%BA%D0%B0","aria-hidden":"true"}},[a._v("#")]),a._v("Основные характеристики и принципы языка")]),t("ol",[t("li",[t("p",[a._v("Кроссплатформенность\nдостигается за счет использования виртуальной машины JVM, которая является обычной программой, исполняемой операционной системой и предоставляющей Java -приложениям все необходимые возможности. \nПоскольку все параметры JVM специфицированы, то остается единственная задача - реализовать виртуальные машины на всех существующих и используемых платформах.")])]),t("li",[t("p",[a._v("Компилируемый или интерпретируемый язык")])])]),t("p",[a._v("На самом деле, используются оба подхода.")]),t("p",[a._v("Исходный код любой программы на языке Java представляется обычными текстовыми файлами, которые могут быть созданы в любом текстовом редакторе или специализированном средстве разработки и имеют расширение .java. Эти файлы подаются на вход Java -компилятора, который транслирует их в специальный Java байт-код. Именно этот компактный и эффективный набор инструкций поддерживается JVM и является неотъемлемой частью платформы Java.")]),t("p",[a._v("Результат работы компилятора сохраняется в бинарных файлах с расширением .class. Java -приложение, состоящее из таких файлов, подается на вход виртуальной машине, которая начинает их исполнять, или интерпретировать, так как сама является программой.")]),t("ol",{attrs:{start:"3"}},[t("li",[a._v('ООП\nВ Java практически все реализовано в виде объектов - потоки выполнения (threads) и потоки данных (streams), работа с сетью, работа с изображениями, с пользовательским интерфейсом, обработка ошибок и т.д. В конце концов, любое приложение на Java - это набор классов, описывающих новые типы объектов. Создатели отказались от множественного наследования. Было решено, что оно слишком усложняет и запутывает программы. В языке используется альтернативный подход - специальный тип "интерфейс". ')])]),t("p",[a._v("Также, в Java применяется строгая типизация. Это означает, что любая переменная и любое выражение имеет тип, известный уже на момент компиляции. Такой подход применен для упрощения выявления проблем, ведь компилятор сразу сообщает об ошибках и указывает их расположение в коде. Поиск же исключительных ситуаций (exceptions - так в Java называются некорректные ситуации) во время исполнения программы (runtime) потребует сложного тестирования, при этом причина дефекта может обнаружиться совсем в другом классе. Таким образом, нужно прикладывать дополнительные усилия при написании кода, зато существенно повышается его надежность (а это одна из основополагающих целей, для которых и создавался новый язык).")]),t("ol",{attrs:{start:"4"}},[t("li",[a._v("Легкость в освоении и разработке ")])]),t("p",[a._v("Авторы потрудились избавить программистов от наиболее распространенных ошибок, которые порой допускают даже опытные разработчики на C/C++. И первое место здесь занимает работа с памятью.")]),t("p",[a._v("В Java с самого начала был введен механизм автоматической сборки мусора (от английского garbage collector ). Предположим, программа создает некоторый объект, работает с ним, а дальше наступает момент, когда он больше уже не нужен. Необходимо освободить занимаемую память, чтобы не мешать операционной системе нормально функционировать. В С/С++ это необходимо делать явным образом из программы. Очевидно, что при таком подходе существует две опасности - либо удалить объект, который еще кому-то необходим (и если к нему действительно произойдет обращение, то возникнет ошибка), либо не удалять объект, ставший ненужным, а это означает утечку памяти, то есть программа начинает потреблять все большее количество оперативной памяти.")]),t("p",[a._v("При разработке на Java программист вообще не думает об освобождении памяти. Виртуальная машина сама подсчитывает количество ссылок на каждый объект, и если оно становится равным нулю, то такой объект помечается для обработки garbage collector. Таким образом, программист должен следить лишь за тем, чтобы не оставалось ссылок на ненужные объекты. Сборщик мусора - это фоновый поток исполнения, который регулярно просматривает существующие объекты и удаляет уже не нужные. Из программы никак нельзя повлиять на работу garbage collector, можно только явно инициировать его очередной проход с помощью стандартной функции. Ясно, что это существенно упрощает разработку программ, особенно для начинающих программистов.")]),t("p",[a._v("Однако опытные разработчики были недовольны тем, что они не могут полностью контролировать все, что происходит с их системой. Нет точной информации, когда именно будет удален объект, ставший ненужным, когда начнет работать (а значит, и занимать системные ресурсы) поток сборщика мусора и т.д. Но,при всем уважении к опыту таких программистов, необходимо отметить, что подавляющее количество сбоев программ, написанных на С/С++, приходится именно на некорректную работу с памятью, причем порой это случается даже с широко распространенными продуктами весьма серьезных компаний.")]),t("p",[a._v("Кроме того, особый упор делался на легкость освоения новой технологии. Как уже было сказано, ожидалось (и эти ожидания оправдались, в подтверждение правильности выбранного пути!), что Java должна получить максимально широкое применение, даже в тех компаниях, где никогда до этого не занимались программированием на таком уровне (бытовая техника типа тостеров и кофеварок, создание игр и других приложений для сотовых телефонов и т.д.). Был и целый ряд других соображений. Продукты для обычных пользователей, а не профессиональных программистов, должны быть особенно надежными. Internet стал Всемирной Сетью, поскольку появились непрофессиональные пользователи, а возможность создавать апплеты для них не менее привлекательна. Им требовался простой инструмент для создания надежных приложений.")]),t("p",[a._v("Кроме введения garbage collector, были предприняты и другие шаги для облегчения разработки. Некоторые из них уже упоминались - отказ от множественного наследования, упрощение синтаксиса и др. Возможность создания многопоточных приложений была реализована в первой же версии Java (исследования показали, что это очень удобно для пользователей, а существующие стандарты опираются на телетайпные системы, которые устарели много лет назад). Однако то, что создание и поддержка систем действительно проще на Java, чем на C/C++, давно является общепризнанным фактом. Впрочем, все-таки эти языки созданы для разных целей, и каждый имеет свои неоспоримые преимущества.")]),t("ol",{attrs:{start:"5"}},[t("li",[a._v("Безопасность")])]),t("p",[a._v("Изначальная нацеленность на распределенные приложения, и в особенности решение исполнять апплеты на клиентской машине, сделали вопрос защиты одним из самых приоритетных. При работе любой виртуальной машины Java действует целый комплекс мер. Далее приводится лишь краткое описание некоторых из них.")]),t("p",[a._v("Во-первых, это правила работы с памятью. Уже говорилось, что очистка памяти производится автоматически. Резервирование ее также определяется JVM, а не компилятором, или явным образом из программы, разработчик может лишь указать, что он хочет создать еще один новый объект. Указатели по физическим адресам отсутствуют принципиально.")]),t("p",[a._v("Во-вторых, наличие виртуальной машины-интерпретатора значительно облегчает отсечение опасного кода на каждом этапе работы. Сначала байт-код загружается в систему, как правило, в виде class-файлов. JVM тщательно проверяет, все ли они подчиняются общим правилам безопасности Java и не созданы ли злоумышленниками с помощью каких-то других средств (и не искажены ли при передаче). Затем, во время исполнения программы, интерпретатор легко может проверить каждое действие на допустимость. Возможности классов, которые были загружены с локального диска или по сети, существенно различаются (пользователь легко может назначать или отменять конкретные права). Например, апплеты по умолчанию никогда не получат доступ к локальной файловой системе. Такие встроенные ограничения есть во всех стандартных библиотеках Java.")]),t("p",[a._v("Наконец, существует механизм подписания апплетов и других приложений, загружаемых по сети. Специальный сертификат гарантирует, что пользователь получил код именно в том виде, в каком его выпустил производитель. Это, конечно, не дает дополнительных средств защиты, но позволяет клиенту либо отказаться от работы с приложениями ненадежных производителей, либо сразу увидеть, что в программу внесены неавторизованные изменения. В худшем случае он знает, кто ответственен за причиненный ущерб.ъ")]),t("ol",{attrs:{start:"6"}},[t("li",[a._v("Динамичность")])]),t("p",[a._v("Язык очень удачно задуман, в его развитии участвуют сотни тысяч разработчиков и многие крупные компании.")])])}),[],!1,null,null,null);"function"==typeof o&&o(s),"function"==typeof p&&p(s);v.default=s.exports}}]);